import{_ as o,c as e,o as n,ah as r}from"./chunks/framework.RCw5T9E9.js";const m=JSON.parse('{"title":"Расширенный режим захвата (Advanced mode)","description":"","frontmatter":{"title":"Расширенный режим захвата (Advanced mode)"},"headers":[],"relativePath":"ru/network/advanced.md","filePath":"ru/network/advanced.md"}'),s={name:"ru/network/advanced.md"};function d(a,t,g,l,i,c){return n(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="расширенныи-режим-захвата-advanced-mode" tabindex="-1">Расширенный режим захвата (Advanced mode) <a class="header-anchor" href="#расширенныи-режим-захвата-advanced-mode" aria-label="Permalink to &quot;Расширенный режим захвата (Advanced mode)&quot;">​</a></h1><p>В разделе <strong>Options → Network</strong> можно выбрать <strong>режим захвата</strong> сетевого обмена:</p><table tabindex="0"><thead><tr><th>Режим</th><th>В интерфейсе</th><th>Суть</th></tr></thead><tbody><tr><td><strong>Classic mode</strong></td><td>«классический» снимок</td><td>Те же ограничения, что у перехвата на странице: видны заголовки и тело в объёме, доступном скрипту страницы (в т.ч. правила <strong>CORS</strong> для чужого origin). Подробнее см. <a href="./general.html#ограничения-отображения">Работа с запросами</a>.</td></tr><tr><td><strong>Advanced mode</strong></td><td>расширенный захват</td><td>Расширение запрашивает доступ к <strong><code>webRequest</code></strong> и дополняет карточку запроса <strong>полным набором заголовков</strong> запроса и ответа так, как их видит браузер на уровне обмена, а не только «разрешённый странице» список.</td></tr></tbody></table><p><strong>Advanced mode</strong> (закрепление заголовков, <strong>Header links</strong>, опции <strong>Advanced headers</strong>) доступен <strong>только в расширении</strong> для Chrome / Edge.<br><strong>В Standalone</strong> по-прежнему используется сценарий без расширенного захвата: полный набор заголовков через <strong><code>webRequest</code></strong>, описанный ниже, там <strong>недоступен</strong>.</p><hr><h2 id="что-дает-advanced-mode-во-вкладке-network" tabindex="-1">Что даёт Advanced mode во вкладке Network <a class="header-anchor" href="#что-дает-advanced-mode-во-вкладке-network" aria-label="Permalink to &quot;Что даёт Advanced mode во вкладке Network&quot;">​</a></h2><ul><li><strong>Заголовки запроса и ответа</strong> в детализации запроса отражают расширенные данные (в том числе служебные и не попавшие в <code>Access-Control-Expose-Headers</code>).</li><li><strong>Закрепление строк заголовков (pin)</strong> — для имени заголовка можно закрепить строку <strong>вверху списка</strong> отдельно для блока <strong>Request</strong> и отдельно для <strong>Response</strong>. Закрепления выполняются из <strong>меню строки</strong> заголовка (три точки) при активном Advanced mode.</li><li><strong>Header links</strong> — для пары «имя заголовка + <strong>Host</strong> запроса» задаётся шаблон внешнего URL; <strong><code>{value}</code></strong> заменяется значением заголовка, как оно показано в Network.</li></ul><p>Список <strong>Header links</strong>, таблица <strong>Pinned headers</strong> и блок <strong>Advanced headers</strong> в <strong>Options → Network</strong> отображаются <strong>только при включённом Advanced mode</strong>, чтобы не перегружать Classic mode.</p><hr><h2 id="header-links" tabindex="-1">Header links <a class="header-anchor" href="#header-links" aria-label="Permalink to &quot;Header links&quot;">​</a></h2><p>Правило задаёт:</p><ul><li><strong>Header</strong> — имя HTTP-заголовка (сопоставление <strong>без учёта регистра</strong>);</li><li><strong>Host</strong> — хост URL запроса (нормализуется, без схемы и пути, например <code>api.example.com</code>);</li><li><strong>Link</strong> — шаблон URL; <strong><code>{value}</code></strong> заменяется <strong>сырым</strong> значением заголовка из карточки запроса.</li></ul><p>Создание и правка правил доступны из <strong>меню строки заголовка</strong> во вкладке <strong>Network</strong> (Advanced) и из <strong>Options</strong> при выбранной группе правил для заголовка.</p><hr><h2 id="краткая-памятка" tabindex="-1">Краткая памятка <a class="header-anchor" href="#краткая-памятка" aria-label="Permalink to &quot;Краткая памятка&quot;">​</a></h2><ul><li><strong>Advanced mode</strong> расширяет заголовки за счёт <strong><code>webRequest</code></strong>; <strong>Standalone</strong> этого режима не предоставляет.</li><li><strong>Classic mode</strong> — прежняя модель «видимости» заголовков для страницы.</li><li><strong>Pin</strong> — отдельно для списков <strong>Request</strong> / <strong>Response</strong>.</li><li><strong>Header links:</strong> <strong>Host</strong> + шаблон <strong>Link</strong> с <strong><code>{value}</code></strong> для подстановки значения заголовка.</li></ul>',16)])])}const p=o(s,[["render",d]]);export{m as __pageData,p as default};
